#!/usr/bin/env python3"""Portfolio Update - 11 AM Check (Feb 20, 2026)"""import jsonimport osimport sysfrom datetime import datetime
# Load Alpaca APIfrom alpaca.trading.client import TradingClient# Load Alpaca credentialswith open('/Users/mikeclawd/.openclaw/secrets/alpaca.json', 'r') as f:creds = json.load(f)client = TradingClient(creds['apiKey'], creds['apiSecret'], paper=True)# Get fresh positionspositions = client.get_all_positions()# Calculate portfolio statsall_positions = []stop_losses = []profit_targets = []total_value = 0total_pl = 0for pos in positions:symbol = pos.symbolqty = float(pos.qty)avg_entry = float(pos.avg_entry_price)current = float(pos.current_price)unrealized_pl = float(pos.unrealized_pl)unrealized_plpc = float(pos.unrealized_plpc) * 100market_value = float(pos.market_value)total_value += market_valuetotal_pl += unrealized_plall_positions.append({'symbol': symbol,'qty': qty,'avg_entry': avg_entry,'current': current,'plpc': unrealized_plpc,'pl': unrealized_pl,'market_value': market_value})# Check thresholdsif unrealized_plpc <= -15:stop_losses.append({'symbol': symbol, 'plpc': unrealized_plpc})if unrealized_plpc >= 30:profit_targets.append({'symbol': symbol, 'plpc': unrealized_plpc})# Sort positionsall_positions.sort(key=lambda x: x['plpc'], reverse=True)# Count up/downup_positions = sum(1 for p in all_positions if p['plpc'] > 0)down_positions = sum(1 for p in all_positions if p['plpc'] <= 0)# Output JSON resultresult = {'timestamp': datetime.now().isoformat(),'check_type': '11AM Portfolio Check','total_positions': len(positions),'up_positions': up_positions,'down_positions': down_positions,'portfolio_value': round(total_value, 2),'unrealized_pl': round(total_pl, 2),'positions': all_positions,'stop_losses_triggered': stop_losses,'profit_targets_triggered': profit_targets}print(json.dumps(result, indent=2))